INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (122601, 1, 160, 1, 105, 101, 1, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 1, 110, 0, 1.5, 0.029, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (122401, 2, 120, 0, 111, 102, 3, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 2, 105, 1, 2.5, 0.014, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (122501, 3, 350, 0, 105, 103, 2, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 3, 110, 0, 2.5, 0.017, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (107501, 4, 130, 0, 105, 104, 3, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 4, 110, 1, 1.5, 0.016, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (107601, 5, 160, 1, 105, 105, 1, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 5, 110, 0, 2.5, 0.014, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (107801, 6, 255, 0, 103, 106, 2, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 6, 120, 0, 3.5, 0.029, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (110601, 7, 160, 1, 103, 107, 1, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 7, 120, 0, 3.5, 0.013, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (110401, 8, 350, 0, 103, 108, 2, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 8, 110, 0, 2.5, 0.014, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (110501, 9, 130, 0, 100, 109, 3, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 9, 105, 1, 1.5, 0.012, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (115701, 10, 200, 1, 103, 110, 1, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 10, 105, 0, 2.5, 0.014, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (113601, 11, 350, 0, 103, 111, 2, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 11, 105, 0, 2.5, 0.071, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (107901, 12, 130, 0, 103, 112, 3, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 12, 120, 1, 1.5, 0.014, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (108001, 13, 200, 1, 105, 113, 2, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 13, 110, 0, 1.5, 0.022, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (110301, 14, 160, 1, 108, 114, 1, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 14, 110, 0, 2.5, 0.031, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (107701, 15, 130, 0, 105, 115, 1, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 15, 110, 1, 0.5, 0.036, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (113101, 16, 350, 0, 95, 116, 2, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 16, 110, 0, 3.5, 0.048, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (113301, 17, 130, 0, 105, 117, 3, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 17, 105, 1, 1.5, 0.043, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (113201, 18, 130, 0, 95, 118, 2, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 18, 105, 1, 1.5, 0.018, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (117001, 19, 160, 1, 108, 119, 2, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 19, 110, 0, 2.5, 0.021, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (113501, 20, 255, 0, 105, 120, 1, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 20, 110, 0, 2.5, 0.036, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (113401, 21, 350, 0, 105, 121, 3, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 21, 105, 0, 2.5, 0.02, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (110101, 22, 130, 0, 105, 122, 1, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 22, 110, 1, 2.5, 0.018, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (110001, 23, 160, 1, 111, 123, 3, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 23, 105, 0, 3.5, 0.03, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (117201, 24, 130, 0, 103, 124, 1, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 24, 110, 1, 1.5, 0.027, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (117301, 25, 160, 1, 108, 125, 2, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 25, 105, 0, 3.5, 0.02, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (117401, 26, 350, 0, 105, 126, 3, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 26, 110, 0, 2.5, 0.04, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (117101, 27, 350, 0, 105, 127, 1, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 27, 110, 0, 3.5, 0.009, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (122901, 28, 255, 0, 105, 128, 1, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 28, 120, 0, 3.5, 0.022, 1);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (122801, 29, 130, 0, 105, 129, 3, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 29, 110, 1, 2.5, 0.028, 0);
INSERT INTO `v1_0eba109be15b8f971be6428cbcc30c2184459e723bd3bc73856fb9d51cb99ffe` VALUES (122701, 30, 130, 1, 108, 130, 2, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 30, 105, 0, 3.5, 0.023, 0);
